{
  "title": "Pasted Exam",
   "description": "Comprehensive exam covering various subjects",
   "timeLimit": 60,
   "passingScore": 70,
   "sections": [
       {
           "name": "A",
           "description": "COMPREHENSION",
           "questions": [
               {
                   "text": "What is the name of the school?",
                   "type": "short-answer",
                   "points": 2,
                   "correctAnswer": "Sunrise Primary School"
               },
               {
                   "text": "Who does Keza walk to school with?",
                   "type": "short-answer",
                   "points": 2,
                   "correctAnswer": "Her brother"
               },
               {
                   "text": "How long does it take Keza to reach school?",
                   "type": "short-answer",
                   "points": 2,
                   "correctAnswer": "Twenty minutes"
               },
               {
                   "text": "What is Keza’s favourite subject?",
                   "type": "short-answer",
                   "points": 2,
                   "correctAnswer": "English"
               },
               {
                   "text": "Why does Keza like the subject?",
                   "type": "short-answer",
                   "points": 2,
                   "correctAnswer": "She enjoys reading stories"
               },
               {
                   "text": "Mention two things found at Keza’s school.",
                   "type": "short-answer",
                   "points": 4,
                   "correctAnswer": "Library and classrooms"
               },
               {
                   "text": "What does Keza do after lessons?",
                   "type": "short-answer",
                   "points": 2,
                   "correctAnswer": "She plays football"
               },
               {
                   "text": "Do you enjoy playing with friends after school? Why?",
                   "type": "open-ended",
                   "points": 4
               }
           ]
       },
       {
           "name": "B",
           "description": "VOCABULARY",
           "questions": [
               {
                   "text": "Match the words with their meanings.",
                   "type": "matching",
                   "points": 5,
                   "options": [
                       {"text": "1. Doctor", "meaning": "b. A person who treats sick people"},
                       {"text": "2. School", "meaning": "a. A place where children learn"},
                       {"text": "3. Market", "meaning": "c. A place where people buy and sell things"},
                       {"text": "4. Library", "meaning": "d. A place with books"},
                       {"text": "5. Farmer", "meaning": "e. A person who grows crops"}
                   ]
               },
               {
                   "text": "Fill in the blanks using the correct words from the box.",
                   "type": "fill-in-blank",
                   "points": 10,
                   "correctAnswers": [
                       {"blank": "We read books in the ____________.", "answer": "library"},
                       {"blank": "Children play football in the ____________.", "answer": "playground"},
                       {"blank": "It is ____________ today. I can see the sun.", "answer": "sunny"},
                       {"blank": "The girls are ____________ songs.", "answer": "singing"},
                       {"blank": "We carry umbrellas when it is ____________.", "answer": "rainy"}
                   ]
               }
           ]
       },
       {
           "name": "C",
           "description": "GRAMMAR",
           "questions": [
               {
                   "text": "Write the negative form of the following sentences.",
                   "type": "short-answer",
                   "points": 5,
                   "correctAnswers": [
                       {"sentence": "She likes English.", "negative": "She does not like English."},
                       {"sentence": "They play football every day.", "negative": "They do not play football every day."},
                       {"sentence": "He walks to school.", "negative": "He does not walk to school."},
                       {"sentence": "We study Mathematics.", "negative": "We do not study Mathematics."},
                       {"sentence": "Aline enjoys dancing.", "negative": "Aline does not enjoy dancing."}
                   ]
               },
               {
                   "text": "Write questions using the words given.",
                   "type": "short-answer",
                   "points": 5,
                   "correctAnswers": [
                       {"words": "you / like / English", "question": "Do you like English?"},
                       {"words": "she / go / to school", "question": "Does she go to school?"},
                       {"words": "they / play / football", "question": "Do they play football?"},
                       {"words": "he / enjoy / reading", "question": "Does he enjoy reading?"},
                       {"words": "we / study / Science", "question": "Do we study Science?"}
                   ]
               },
               {
                   "text": "Fill in the blanks with the correct form of the verbs in brackets.",
                   "type": "fill-in-blank",
                   "points": 10,
                   "correctAnswers": [
                       {"blank": "She ____________ (walk) to school every day.", "answer": "walks"},
                       {"blank": "We ____________ (study) English on Monday.", "answer": "study"},
                       {"blank": "He ____________ (like) football.", "answer": "likes"},
                       {"blank": "They ____________ (play) in the playground.", "answer": "play"},
                       {"blank": "Does she ____________ (teach) English?", "answer": "teach"}
                   ]
               },
               {
                   "text": "Choose the correct answer.",
                   "type": "multiple-choice",
                   "points": 5,
                   "options": [
                       {
                           "text": "There ____ many books in the library.",
                           "options": [
                               {"text": "a) is", "isCorrect": false},
                               {"text": "b) are", "isCorrect": true},
                               {"text": "c) am", "isCorrect": false}
                           ]
                       },
                       {
                           "text": "The school is ____ the market.",
                           "options": [
                               {"text": "a) behind", "isCorrect": true},
                               {"text": "b) eat", "isCorrect": false},
                               {"text": "c) run", "isCorrect": false}
                           ]
                       },
                       {
                           "text": "It ____ rainy yesterday.",
                           "options": [
                               {"text": "a) is", "isCorrect": false},
                               {"text": "b) was", "isCorrect": true},
                               {"text": "c) are", "isCorrect": false}
                           ]
                       },
                       {
                           "text": "She is taller ____ Aline.",
                           "options": [
                               {"text": "a) than", "isCorrect": true},
                               {"text": "b) then", "isCorrect": false},
                               {"text": "c) that", "isCorrect": false}
                           ]
                       },
                       {
                           "text": "I am going to ____ my grandmother.",
                           "options": [
                               {"text": "a) visits", "isCorrect": false},
                               {"text": "b) visiting", "isCorrect": false},
                               {"text": "c) visit", "isCorrect": true}
                           ]
                       }
                   ]
               }
           ]
       },
       {
           "name": "D",
           "description": "WEATHER",
           "questions": [
               {
                   "text": "Mention four types of weather.",
                   "type": "short-answer",
                   "points": 4
               },
               {
                   "text": "What do people wear when it is cold?",
                   "type": "short-answer",
                   "points": 2
               },
               {
                   "text": "What was the weather like yesterday? Write one sentence.",
                   "type": "short-answer",
                   "points": 2
               },
               {
                   "text": "Why is weather important?",
                   "type": "short-answer",
                   "points": 2
               }
           ]
       },
       {
           "name": "E",
           "description": "WRITING",
           "questions": [
               {
                   "text": "Write five sentences about your school.",
                   "type": "open-ended",
                   "points": 10
               },
               {
                   "text": "Write five sentences about what you did last weekend.",
                   "type": "open-ended",
                   "points": 10
               }
           ]
       },
       {
           "name": "F",
           "description": "ATTITUDES AND VALUES",
           "questions": [
               {
                   "text": "Write two ways you can help keep your school clean.",
                   "type": "short-answer",
                   "points": 4
               },
               {
                   "text": "Write two qualities of a good friend.",
                   "type": "short-answer",
                   "points": 4
               },
               {
                   "text": "Why is it important to come to school on time?",
                   "type": "short-answer",
                   "points": 2
               }
           ]
       }
   ]
